<section class="auth-section"><form method="post" action="<?= base_url('index.php?route=reset-password/submit') ?>" class="auth-card"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><input type="hidden" name="token" value="<?= e($token ?? '') ?>"><h2>Reset Password</h2><?php if (empty($reset)): ?><p class="text-danger">Invalid or expired token.</p><?php else: ?><p>Set a new password for <?= e($reset['email']) ?>.</p><div class="form-group"><label>New Password</label><input type="password" name="password" required></div><div class="form-group"><label>Confirm Password</label><input type="password" name="confirm_password" required></div><button class="btn btn-primary w-full" type="submit">Reset Password</button><?php endif; ?></form></section>
